import React, { useState, useEffect } from 'react';
import { Home, LayoutDashboard, ShieldAlert, Music, Upload, Info } from 'lucide-react';
import * as Sentry from '@sentry/react';
import Navbar from './components/Navbar';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import MusicLibrary from './components/MusicLibrary';
import AdminDashboard from './components/AdminDashboard';
import AboutPage from './components/AboutPage';
import UploadModal from './components/UploadModal';
import AuthModal from './components/AuthModal';
import FullPreviewPage from './components/FullPreviewPage';
import { View, MusicSheet } from './types';
import { auth, db } from './firebase';
// Fix: Removed missing modular auth exports; using instance methods instead.
import { collection, onSnapshot, query, orderBy, where, limit } from 'firebase/firestore';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [activePreview, setActivePreview] = useState<MusicSheet | null>(null);
  const [sheets, setSheets] = useState<MusicSheet[]>([]);

  const [currentUser, setCurrentUser] = useState<{ email: string; role: 'admin' | 'user'; emailVerified: boolean } | null>(null);

  useEffect(() => {
    let q;

    if (currentView === 'admin' && currentUser?.role === 'admin') {
      q = query(collection(db, 'sheets'), orderBy('createdAt', 'desc'));
    } else if (currentView === 'dashboard' && currentUser) {
      q = query(
        collection(db, 'sheets'), 
        where('uploadedBy', '==', currentUser.email), 
        orderBy('createdAt', 'desc')
      );
    } else {
      q = query(
        collection(db, 'sheets'), 
        where('isPublic', '==', true), 
        orderBy('createdAt', 'desc')
      );
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const sheetsData = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as MusicSheet[];

      setSheets(sheetsData);
    }, (error) => {
      console.error("Firestore sync error:", error);
      // Report database failures to Sentry
      Sentry.captureException(error, {
        tags: {
          view: currentView,
          userRole: currentUser?.role || 'guest'
        }
      });

      const fallbackQ = query(collection(db, 'sheets'), limit(100));
      onSnapshot(fallbackQ, (snapshot) => {
        const sheetsData = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })) as MusicSheet[];
        setSheets(sheetsData);
      });
    });

    return () => unsubscribe();
  }, [currentView, currentUser]);

  useEffect(() => {
    // Fix: Use instance method for onAuthStateChanged
    const unsubscribe = auth.onAuthStateChanged((user) => {
      if (user && user.email) {
        const role = user.email === 'vitalisnkwenti@gmail.com' ? 'admin' : 'user';
        setCurrentUser({ email: user.email, role, emailVerified: user.emailVerified });
      } else {
        setCurrentUser(null);
      }
    });
    return () => unsubscribe();
  }, []);

  const handleOpenLogin = () => {
    setIsAuthModalOpen(true);
  };

  const handleLogout = async () => {
    try {
      // Fix: Use instance method for signOut
      await auth.signOut();
      setCurrentView('home');
      setActivePreview(null);
    } catch (error) {
      console.error("Error signing out: ", error);
      Sentry.captureException(error);
    }
  };

  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  const handleHomeSearch = (query: string) => {
    setSearchQuery(query);
    setCurrentView('library');
  };

  const handlePreview = (sheet: MusicSheet) => {
    setActivePreview(sheet);
  };

  useEffect(() => {
    if (!currentUser && (currentView === 'dashboard' || currentView === 'admin')) {
      setCurrentView('home');
    }
    if (currentUser && currentUser.role !== 'admin' && currentView === 'admin') {
      setCurrentView('home');
    }
  }, [currentUser, currentView]);

  const renderView = () => {
    switch (currentView) {
      case 'home':
        return (
          <LandingPage 
            onUploadClick={currentUser ? () => setIsUploadModalOpen(true) : handleOpenLogin} 
            onBrowseClick={() => { setSearchQuery(''); setCurrentView('library'); }} 
            onSearch={handleHomeSearch}
            onPreview={handlePreview}
            isLoggedIn={!!currentUser}
            darkMode={darkMode}
            sheets={sheets}
          />
        );
      case 'dashboard':
        return currentUser ? (
          <Dashboard 
            onUploadClick={() => setIsUploadModalOpen(true)} 
            onPreview={handlePreview} 
            darkMode={darkMode}
            sheets={sheets}
            userEmail={currentUser.email}
          />
        ) : null;
      case 'library':
        return <MusicLibrary darkMode={darkMode} initialSearch={searchQuery} onPreview={handlePreview} sheets={sheets} />;
      case 'admin':
        return currentUser?.role === 'admin' ? (
          <AdminDashboard 
            onPreview={handlePreview} 
            darkMode={darkMode} 
            sheets={sheets}
          />
        ) : null;
      case 'about':
        return <AboutPage darkMode={darkMode} />;
      default:
        return <LandingPage 
          onUploadClick={currentUser ? () => setIsUploadModalOpen(true) : handleOpenLogin} 
          onBrowseClick={() => { setSearchQuery(''); setCurrentView('library'); }} 
          onSearch={handleHomeSearch}
          onPreview={handlePreview}
          isLoggedIn={!!currentUser}
          darkMode={darkMode}
          sheets={sheets}
        />;
    }
  };

  const themeClasses = darkMode 
    ? "bg-slate-950 text-slate-100" 
    : "bg-slate-50 text-slate-900";

  return (
    <div className={`min-h-screen transition-colors duration-300 selection:bg-green-500/30 selection:text-green-200 font-sans ${themeClasses}`}>
      {activePreview ? (
        <FullPreviewPage 
          sheet={activePreview} 
          darkMode={darkMode} 
          onThemeToggle={toggleTheme} 
          onClose={() => setActivePreview(null)}
          isLoggedIn={!!currentUser}
          onAuthRequired={() => setIsAuthModalOpen(true)}
        />
      ) : (
        <>
          <Navbar 
            activeView={currentView} 
            onViewChange={(view) => { setCurrentView(view); setActivePreview(null); }} 
            currentUser={currentUser}
            onLogout={handleLogout}
            onLogin={handleOpenLogin}
            darkMode={darkMode}
            onThemeToggle={toggleTheme}
          />

          <main className="max-w-7xl mx-auto px-4 pt-3 pb-12 lg:py-12 pb-24">
            {renderView()}
          </main>

          <div className={`md:hidden fixed bottom-0 left-0 right-0 backdrop-blur-lg border-t p-2 flex justify-around items-center z-50 ${darkMode ? 'bg-slate-950/80 border-slate-800' : 'bg-white/80 border-slate-200 shadow-lg'}`}>
            <button onClick={() => { setCurrentView('home'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'home' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Home size={24} />
            </button>
            <button onClick={() => { setSearchQuery(''); setCurrentView('library'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'library' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Music size={24} />
            </button>
            <button onClick={() => { setCurrentView('about'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'about' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Info size={24} />
            </button>
            {currentUser && (
              <>
                <button onClick={() => setIsUploadModalOpen(true)} className="p-3 bg-green-500 text-slate-950 rounded-xl shadow-lg shadow-green-500/20 active:scale-95 transition-transform">
                  <Upload size={24} />
                </button>
                <button onClick={() => { setCurrentView('dashboard'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'dashboard' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                  <LayoutDashboard size={24} />
                </button>
                {currentUser.role === 'admin' && (
                  <button onClick={() => { setCurrentView('admin'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'admin' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                    <ShieldAlert size={24} />
                  </button>
                )}
              </>
            )}
          </div>
        </>
      )}

      <UploadModal 
        isOpen={isUploadModalOpen} 
        onClose={() => setIsUploadModalOpen(false)} 
        darkMode={darkMode}
        userEmail={currentUser?.email || ''}
        isVerified={currentUser?.emailVerified || currentUser?.email === 'vitalisnkwenti@gmail.com'}
      />

      <AuthModal 
        isOpen={isAuthModalOpen}
        onClose={() => setIsAuthModalOpen(false)}
        darkMode={darkMode}
      />
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { X, Upload, FileText, Check, Loader2, AlertCircle, Mail, RefreshCw } from 'lucide-react';
import * as Sentry from '@sentry/react';
import { auth, db, storage } from '../firebase';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
// Fix: Removed missing modular auth export.

interface UploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  darkMode: boolean;
  userEmail: string;
  isVerified: boolean;
}

const UploadModal: React.FC<UploadModalProps> = ({ isOpen, onClose, darkMode, userEmail, isVerified }) => {
  const [file, setFile] = useState<File | null>(null);
  const [title, setTitle] = useState('');
  const [composer, setComposer] = useState('');
  const [type, setType] = useState('classical');
  const [isPublic, setIsPublic] = useState(true);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState('');
  const [resending, setResending] = useState(false);
  const [resendStatus, setResendStatus] = useState<string | null>(null);

  const overlayRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === overlayRef.current && !isUploading) {
      onClose();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      if (selectedFile.type === 'application/pdf') {
        setFile(selectedFile);
      } else {
        alert("Please select a valid PDF file.");
      }
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const handleResendVerification = async () => {
    if (auth.currentUser) {
      setResending(true);
      try {
        // Fix: Use instance method for email verification
        await auth.currentUser.sendEmailVerification();
        setResendStatus("Verification email sent! Please check your inbox.");
      } catch (err: any) {
        setResendStatus("Error sending email: " + err.message);
        Sentry.captureException(err);
      } finally {
        setResending(false);
      }
    }
  };

  const generateThumbnail = async (pdfFile: File): Promise<Blob> => {
    try {
      const arrayBuffer = await pdfFile.arrayBuffer();
      const pdfjsLib = (window as any)['pdfjsLib'];
      if (!pdfjsLib) throw new Error('PDF.js library not found. Please refresh and try again.');

      pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

      const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
      const pdf = await loadingTask.promise;
      const page = await pdf.getPage(1);

      const scale = 1.5;
      const viewport = page.getViewport({ scale });
      const canvas = document.createElement('canvas');
      const context = canvas.getContext('2d');

      if (!context) throw new Error('Could not create canvas context');

      canvas.height = viewport.height;
      canvas.width = viewport.width;

      await page.render({ canvasContext: context, viewport }).promise;

      return new Promise((resolve, reject) => {
        canvas.toBlob((blob) => {
          if (blob) resolve(blob);
          else reject(new Error('Thumbnail generation failed'));
        }, 'image/jpeg', 0.85);
      });
    } catch (err) {
      console.error('Thumbnail generation error:', err);
      Sentry.captureException(err, {
        extra: {
          fileName: pdfFile.name,
          fileSize: pdfFile.size
        }
      });
      throw err;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file || !title || !composer) return;

    setIsUploading(true);
    setUploadStatus('Initializing...');

    try {
      setUploadStatus('Generating thumbnail...');
      const thumbnailBlob = await generateThumbnail(file);

      const timestamp = Date.now();

      setUploadStatus('Uploading music sheet...');
      const pdfPath = `sheets/${userEmail}/${timestamp}_${file.name}`;
      const pdfStorageRef = ref(storage, pdfPath);
      const pdfUploadResult = await uploadBytes(pdfStorageRef, file, { contentType: 'application/pdf' });
      const pdfUrl = await getDownloadURL(pdfUploadResult.ref);

      setUploadStatus('Saving preview image...');
      const thumbPath = `thumbnails/${userEmail}/${timestamp}_thumb.jpg`;
      const thumbStorageRef = ref(storage, thumbPath);
      const thumbUploadResult = await uploadBytes(thumbStorageRef, thumbnailBlob, { contentType: 'image/jpeg' });
      const thumbnailUrl = await getDownloadURL(thumbUploadResult.ref);

      setUploadStatus('Finalizing...');
      await addDoc(collection(db, 'sheets'), {
        title,
        composer,
        type: type.charAt(0).toUpperCase() + type.slice(1),
        uploadedAt: new Date().toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' }).replace(',', ''),
        fileSize: formatFileSize(file.size),
        views: 0,
        downloads: 0,
        isPublic,
        isAdminRestricted: false,
        thumbnailUrl: thumbnailUrl,
        pdfUrl: pdfUrl,
        uploadedBy: userEmail,
        createdAt: serverTimestamp()
      });

      onClose();
      setFile(null);
      setTitle('');
      setComposer('');
      setType('classical');
      setUploadStatus('');
    } catch (error: any) {
      console.error("Upload error:", error);
      Sentry.captureException(error);
      alert("Failed to upload music sheet. Our engineering team has been notified. Please try again.");
    } finally {
      setIsUploading(false);
      setUploadStatus('');
    }
  };

  const bgClass = darkMode ? 'bg-[#0f172a] border-slate-800' : 'bg-white border-slate-200 shadow-2xl';
  const textPrimary = darkMode ? 'text-slate-100' : 'text-slate-900';
  const textSecondary = darkMode ? 'text-slate-400' : 'text-slate-600';
  const inputBg = darkMode ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-200';

  return (
    <div 
      ref={overlayRef}
      onClick={handleOverlayClick}
      className="fixed inset-0 z-[100] flex items-center justify-center px-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200"
    >
      <div className={`w-full max-w-xl rounded-2xl overflow-hidden border animate-in zoom-in-95 duration-200 ${bgClass}`}>
        <div className={`flex items-center justify-between p-6 border-b ${darkMode ? 'border-slate-800' : 'border-slate-100'}`}>
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-green-500/10 rounded-full flex items-center justify-center">
              <Upload className="text-green-500" size={20} />
            </div>
            <div>
              <h2 className={`text-xl font-bold ${textPrimary}`}>Upload a New Music Sheet</h2>
              <p className={`text-sm ${textSecondary}`}>Fill out the details below to add a new piece to the sanctuary.</p>
            </div>
          </div>
          <button onClick={onClose} disabled={isUploading} className="text-slate-400 hover:text-green-500 transition-colors disabled:opacity-50">
            <X size={20} />
          </button>
        </div>

        {!isVerified ? (
          <div className="p-12 text-center space-y-6">
            <div className={`w-20 h-20 rounded-3xl flex items-center justify-center mx-auto ${darkMode ? 'bg-amber-500/10' : 'bg-amber-50'}`}>
              <Mail className="text-amber-500" size={40} />
            </div>
            <div className="space-y-2">
              <h3 className={`text-2xl font-serif font-bold ${textPrimary}`}>Verification Required</h3>
              <p className={`max-w-xs mx-auto ${textSecondary}`}>
                Please verify your email address (<b>{userEmail}</b>) before uploading music sheets to the sanctuary.
              </p>
            </div>

            {resendStatus && (
              <div className="p-3 rounded-lg bg-green-500/10 border border-green-500/20 text-green-500 text-sm">
                {resendStatus}
              </div>
            )}

            <div className="flex flex-col gap-3">
              <button 
                onClick={handleResendVerification}
                disabled={resending}
                className="w-full py-3.5 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2"
              >
                {resending ? <RefreshCw className="animate-spin" size={20} /> : <Mail size={20} />}
                Resend Verification Email
              </button>
              <button 
                onClick={onClose}
                className={`w-full py-3.5 font-bold rounded-xl border transition-all ${darkMode ? 'border-slate-800 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-600 hover:text-slate-900'}`}
              >
                Maybe Later
              </button>
            </div>
          </div>
        ) : (
          <form className="p-6 space-y-6" onSubmit={handleSubmit}>
            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Title</label>
              <input 
                type="text" 
                required
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="e.g. Behold Our God"
                className={`w-full rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-white' : 'text-black'}`}
              />
            </div>

            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Composed by</label>
              <input 
                type="text" 
                required
                value={composer}
                onChange={(e) => setComposer(e.target.value)}
                placeholder="e.g. Peter Kwo"
                className={`w-full rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-white' : 'text-black'}`}
              />
            </div>

            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Music Type</label>
              <select 
                value={type}
                onChange={(e) => setType(e.target.value)}
                className={`w-full rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all appearance-none cursor-pointer ${inputBg} ${darkMode ? 'text-white' : 'text-black'}`}
              >
                <option value="classical">Classical</option>
                <option value="liturgical">Liturgical</option>
                <option value="choral">Choral</option>
                <option value="contemporary">Contemporary</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Sheet Music File</label>
              <div 
                onClick={() => !isUploading && fileInputRef.current?.click()}
                className={`border-2 border-dashed rounded-lg p-8 flex flex-col items-center justify-center gap-2 hover:border-green-500/50 transition-colors cursor-pointer group ${darkMode ? 'border-slate-800' : 'border-slate-200'} ${file ? 'border-green-500/50 bg-green-500/5' : ''}`}
              >
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-colors ${darkMode ? 'bg-slate-900 group-hover:bg-slate-800' : 'bg-slate-50 group-hover:bg-slate-100'}`}>
                  {file ? <Check className="text-green-500" size={24} /> : <FileText className="text-slate-400" size={24} />}
                </div>
                <p className={`text-sm ${textSecondary}`}>
                  <span className={`font-medium ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}>
                    {file ? file.name : 'Click to upload'}
                  </span> {file ? '' : 'or drag and drop'}
                </p>
                <p className="text-xs text-slate-500">
                  {file ? `${formatFileSize(file.size)} • Ready` : 'Upload a PDF file. Max size 10MB.'}
                </p>
                <input 
                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept=".pdf"
                  className="hidden" 
                />
              </div>
            </div>

            <div className={`p-4 rounded-xl border flex items-center justify-between ${darkMode ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-200 shadow-inner'}`}>
              <div>
                <p className={`font-medium ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}>Make Public</p>
                <p className="text-xs text-slate-500">Allow anyone to view and download this sheet music.</p>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input 
                  type="checkbox" 
                  className="sr-only peer" 
                  checked={isPublic}
                  onChange={(e) => setIsPublic(e.target.checked)}
                />
                <div className="w-11 h-6 bg-slate-400 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-5 after:transition-all peer-checked:bg-green-500"></div>
              </label>
            </div>

            <button 
              type="submit"
              disabled={isUploading || !file}
              className="w-full py-3 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl transition-all shadow-lg active:scale-95 shadow-green-500/20 disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {isUploading ? (
                <>
                  <Loader2 className="animate-spin" size={20} /> 
                  {uploadStatus || 'Uploading...'}
                </>
              ) : 'Upload'}
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

