              <p className={`text-sm ${textSecondary}`}>Fill out the details below to add a new piece to the sanctuary.</p>
            </div>
          </div>
          <button onClick={onClose} disabled={isUploading} className="text-slate-400 hover:text-green-500 transition-colors disabled:opacity-50">
            <X size={20} />
          </button>
        </div>

        {!isVerified ? (
          <div className="p-12 text-center space-y-6">
            <div className={`w-20 h-20 rounded-3xl flex items-center justify-center mx-auto ${darkMode ? 'bg-amber-500/10' : 'bg-amber-50'}`}>
              <Mail className="text-amber-500" size={40} />
            </div>
            <div className="space-y-2">
              <h3 className={`text-2xl font-serif font-bold ${textPrimary}`}>Verification Required</h3>
              <p className={`max-w-xs mx-auto ${textSecondary}`}>
                Please verify your email address (<b>{userEmail}</b>) before uploading music sheets to the sanctuary.
              </p>
            </div>

            {resendStatus && (
              <div className="p-3 rounded-lg bg-green-500/10 border border-green-500/20 text-green-500 text-sm">
                {resendStatus}
              </div>
            )}

            <div className="flex flex-col gap-3">
              <button 
                onClick={handleResendVerification}
                disabled={resending}
                className="w-full py-3.5 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2"
              >
                {resending ? <RefreshCw className="animate-spin" size={20} /> : <Mail size={20} />}
                Resend Verification Email
              </button>
              <button 
                onClick={onClose}
                className={`w-full py-3.5 font-bold rounded-xl border transition-all ${darkMode ? 'border-slate-800 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-600 hover:text-slate-900'}`}
              >
                Maybe Later
              </button>
            </div>
          </div>
        ) : (
          <form className="p-6 space-y-6" onSubmit={handleSubmit}>
            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Title</label>
              <input 
                type="text" 
                required
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="e.g. Behold Our God"
                className={`w-full rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-white' : 'text-black'}`}
              />
            </div>

            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Composed by</label>
              <input 
                type="text" 
                required
                value={composer}
                onChange={(e) => setComposer(e.target.value)}
                placeholder="e.g. Peter Kwo"
                className={`w-full rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-white' : 'text-black'}`}
              />
            </div>

            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Music Type</label>
              <select 
                value={type}
                onChange={(e) => setType(e.target.value)}
                className={`w-full rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all appearance-none cursor-pointer ${inputBg} ${darkMode ? 'text-white' : 'text-black'}`}
              >
                <option value="classical">Classical</option>
                <option value="liturgical">Liturgical</option>
                <option value="choral">Choral</option>
                <option value="contemporary">Contemporary</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-slate-700'}`}>Sheet Music File</label>
              <div 
                onClick={() => !isUploading && fileInputRef.current?.click()}
                className={`border-2 border-dashed rounded-lg p-8 flex flex-col items-center justify-center gap-2 hover:border-green-500/50 transition-colors cursor-pointer group ${darkMode ? 'border-slate-800' : 'border-slate-200'} ${file ? 'border-green-500/50 bg-green-500/5' : ''}`}
              >
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-colors ${darkMode ? 'bg-slate-900 group-hover:bg-slate-800' : 'bg-slate-50 group-hover:bg-slate-100'}`}>
                  {file ? <Check className="text-green-500" size={24} /> : <FileText className="text-slate-400" size={24} />}
                </div>
                <p className={`text-sm ${textSecondary}`}>
                  <span className={`font-medium ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}>
                    {file ? file.name : 'Click to upload'}
                  </span> {file ? '' : 'or drag and drop'}
                </p>
                <p className="text-xs text-slate-500">
                  {file ? `${formatFileSize(file.size)} • Ready` : 'Upload a PDF file. Max size 10MB.'}
                </p>
                <input 
                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept=".pdf"
                  className="hidden" 
                />
              </div>
            </div>

            <div className={`p-4 rounded-xl border flex items-center justify-between ${darkMode ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-200 shadow-inner'}`}>
              <div>
                <p className={`font-medium ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}>Make Public</p>
                <p className="text-xs text-slate-500">Allow anyone to view and download this sheet music.</p>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input 
                  type="checkbox" 
                  className="sr-only peer" 
                  checked={isPublic}
                  onChange={(e) => setIsPublic(e.target.checked)}
                />
                <div className="w-11 h-6 bg-slate-400 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-5 after:transition-all peer-checked:bg-green-500"></div>
              </label>
            </div>

            <button 
              type="submit"
              disabled={isUploading || !file}
              className="w-full py-3 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl transition-all shadow-lg active:scale-95 shadow-green-500/20 disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {isUploading ? (
                <>
                  <Loader2 className="animate-spin" size={20} /> 
                  {uploadStatus || 'Uploading...'}
                </>
              ) : 'Upload'}
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default UploadModal;

import React, { useState, useEffect } from 'react';
import { Home, LayoutDashboard, ShieldAlert, Music, Upload, Info } from 'lucide-react';
import * as Sentry from '@sentry/react';
import Navbar from './components/Navbar';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import MusicLibrary from './components/MusicLibrary';
import AdminDashboard from './components/AdminDashboard';
import AboutPage from './components/AboutPage';
import UploadModal from './components/UploadModal';
import AuthModal from './components/AuthModal';
import FullPreviewPage from './components/FullPreviewPage';
import { View, MusicSheet } from './types';
import { auth, db } from './firebase';
// Use scoped packages to resolve missing export member errors in some environments
import { onAuthStateChanged, signOut } from '@firebase/auth';
import { collection, onSnapshot, query, orderBy, where, limit } from 'firebase/firestore';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [activePreview, setActivePreview] = useState<MusicSheet | null>(null);
  const [sheets, setSheets] = useState<MusicSheet[]>([]);

  const [currentUser, setCurrentUser] = useState<{ email: string; role: 'admin' | 'user'; emailVerified: boolean } | null>(null);

  useEffect(() => {
    let q;

    if (currentView === 'admin' && currentUser?.role === 'admin') {
      q = query(collection(db, 'sheets'), orderBy('createdAt', 'desc'));
    } else if (currentView === 'dashboard' && currentUser) {
      q = query(
        collection(db, 'sheets'), 
        where('uploadedBy', '==', currentUser.email), 
        orderBy('createdAt', 'desc')
      );
    } else {
      q = query(
        collection(db, 'sheets'), 
        where('isPublic', '==', true), 
        orderBy('createdAt', 'desc')
      );
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const sheetsData = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as MusicSheet[];

      setSheets(sheetsData);
    }, (error) => {
      console.error("Firestore sync error:", error);
      Sentry.captureException(error, {
        tags: {
          view: currentView,
          userRole: currentUser?.role || 'guest'
        }
      });

      const fallbackQ = query(collection(db, 'sheets'), limit(100));
      onSnapshot(fallbackQ, (snapshot) => {
        const sheetsData = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })) as MusicSheet[];
        setSheets(sheetsData);
      });
    });

    return () => unsubscribe();
  }, [currentView, currentUser]);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (user && user.email) {
        const role = user.email === 'vitalisnkwenti@gmail.com' ? 'admin' : 'user';
        setCurrentUser({ email: user.email, role, emailVerified: user.emailVerified });
      } else {
        setCurrentUser(null);
      }
    });
    return () => unsubscribe();
  }, []);

  const handleOpenLogin = () => {
    setIsAuthModalOpen(true);
  };

  const handleLogout = async () => {
    try {
      await signOut(auth);
      setCurrentView('home');
      setActivePreview(null);
    } catch (error) {
      console.error("Error signing out: ", error);
      Sentry.captureException(error);
    }
  };

  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  const handleHomeSearch = (query: string) => {
    setSearchQuery(query);
    setCurrentView('library');
  };

  const handlePreview = (sheet: MusicSheet) => {
    setActivePreview(sheet);
  };

  useEffect(() => {
    if (!currentUser && (currentView === 'dashboard' || currentView === 'admin')) {
      setCurrentView('home');
    }
    if (currentUser && currentUser.role !== 'admin' && currentView === 'admin') {
      setCurrentView('home');
    }
  }, [currentUser, currentView]);

  const renderView = () => {
    switch (currentView) {
      case 'home':
        return (
          <LandingPage 
            onUploadClick={currentUser ? () => setIsUploadModalOpen(true) : handleOpenLogin} 
            onBrowseClick={() => { setSearchQuery(''); setCurrentView('library'); }} 
            onSearch={handleHomeSearch}
            onPreview={handlePreview}
            isLoggedIn={!!currentUser}
            darkMode={darkMode}
            sheets={sheets}
          />
        );
      case 'dashboard':
        return currentUser ? (
          <Dashboard 
            onUploadClick={() => setIsUploadModalOpen(true)} 
            onPreview={handlePreview} 
            darkMode={darkMode}
            sheets={sheets}
            userEmail={currentUser.email}
          />
        ) : null;
      case 'library':
        return <MusicLibrary darkMode={darkMode} initialSearch={searchQuery} onPreview={handlePreview} sheets={sheets} />;
      case 'admin':
        return currentUser?.role === 'admin' ? (
          <AdminDashboard 
            onPreview={handlePreview} 
            darkMode={darkMode} 
            sheets={sheets}
          />
        ) : null;
      case 'about':
        return <AboutPage darkMode={darkMode} />;
      default:
        return <LandingPage 
          onUploadClick={currentUser ? () => setIsUploadModalOpen(true) : handleOpenLogin} 
          onBrowseClick={() => { setSearchQuery(''); setCurrentView('library'); }} 
          onSearch={handleHomeSearch}
          onPreview={handlePreview}
          isLoggedIn={!!currentUser}
          darkMode={darkMode}
          sheets={sheets}
        />;
    }
  };

  const themeClasses = darkMode 
    ? "bg-slate-950 text-slate-100" 
    : "bg-slate-50 text-slate-900";

  return (
    <div className={`min-h-screen transition-colors duration-300 selection:bg-green-500/30 selection:text-green-200 font-sans ${themeClasses}`}>
      {activePreview ? (
        <FullPreviewPage 
          sheet={activePreview} 
          darkMode={darkMode} 
          onThemeToggle={toggleTheme} 
          onClose={() => setActivePreview(null)}
          isLoggedIn={!!currentUser}
          onAuthRequired={() => setIsAuthModalOpen(true)}
        />
      ) : (
        <>
          <Navbar 
            activeView={currentView} 
            onViewChange={(view) => { setCurrentView(view); setActivePreview(null); }} 
            currentUser={currentUser}
            onLogout={handleLogout}
            onLogin={handleOpenLogin}
            darkMode={darkMode}
            onThemeToggle={toggleTheme}
          />

          <main className="max-w-7xl mx-auto px-4 pt-3 pb-12 lg:py-12 pb-24">
            {renderView()}
          </main>

          <div className={`md:hidden fixed bottom-0 left-0 right-0 backdrop-blur-lg border-t p-2 flex justify-around items-center z-50 ${darkMode ? 'bg-slate-950/80 border-slate-800' : 'bg-white/80 border-slate-200 shadow-lg'}`}>
            <button onClick={() => { setCurrentView('home'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'home' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Home size={24} />
            </button>
            <button onClick={() => { setSearchQuery(''); setCurrentView('library'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'library' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Music size={24} />
            </button>
            <button onClick={() => { setCurrentView('about'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'about' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Info size={24} />
            </button>
            {currentUser && (
              <>
                <button onClick={() => setIsUploadModalOpen(true)} className="p-3 bg-green-500 text-slate-950 rounded-xl shadow-lg shadow-green-500/20 active:scale-95 transition-transform">
                  <Upload size={24} />
                </button>
                <button onClick={() => { setCurrentView('dashboard'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'dashboard' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                  <LayoutDashboard size={24} />
                </button>
                {currentUser.role === 'admin' && (
                  <button onClick={() => { setCurrentView('admin'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'admin' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                    <ShieldAlert size={24} />
                  </button>
                )}
              </>
            )}
          </div>
        </>
      )}

      <UploadModal 
        isOpen={isUploadModalOpen} 
        onClose={() => setIsUploadModalOpen(false)} 
        darkMode={darkMode}
        userEmail={currentUser?.email || ''}
        isVerified={currentUser?.emailVerified || currentUser?.email === 'vitalisnkwenti@gmail.com'}
      />

      <AuthModal 
        isOpen={isAuthModalOpen}
        onClose={() => setIsAuthModalOpen(false)}
        darkMode={darkMode}
      />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { X, Mail, Lock, User as UserIcon, LogIn, UserPlus, AlertCircle, CheckCircle, ArrowLeft } from 'lucide-react';
import * as Sentry from '@sentry/react';
import { auth, db } from '../firebase';
import { doc, setDoc, serverTimestamp } from 'firebase/firestore';
// Use scoped package to resolve missing export member errors in some environments
import { 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  updateProfile,
  GoogleAuthProvider,
  signInWithPopup,
  sendPasswordResetEmail,
  sendEmailVerification
} from '@firebase/auth';

interface AuthModalProps {
  isOpen: boolean;
  onClose: () => void;
  darkMode: boolean;
}

const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onClose, darkMode }) => {
  const [mode, setMode] = useState<'signin' | 'signup' | 'reset'>('signin');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const overlayRef = useRef<HTMLDivElement>(null);

  if (!isOpen) return null;

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === overlayRef.current && !loading) {
      onClose();
    }
  };

  const saveUserProfile = async (user: any, name?: string) => {
    const userRef = doc(db, 'users', user.uid);
    await setDoc(userRef, {
      id: user.uid,
      displayName: name || user.displayName || user.email?.split('@')[0] || 'Anonymous User',
      email: user.email,
      role: user.email === 'vitalisnkwenti@gmail.com' ? 'admin' : 'user',
      status: 'Active',
      updatedAt: serverTimestamp(),
    }, { merge: true });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMsg(null);
    setLoading(true);

    try {
      if (mode === 'signup') {
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        if (displayName) {
          await updateProfile(userCredential.user, { displayName });
        }
        await saveUserProfile(userCredential.user, displayName);
        await sendEmailVerification(userCredential.user);
        setSuccessMsg("Account created! A verification email has been sent to " + email + ". Please verify your email before uploading music.");
      } else if (mode === 'signin') {
        await signInWithEmailAndPassword(auth, email, password);
        onClose();
      } else if (mode === 'reset') {
        await sendPasswordResetEmail(auth, email);
        setSuccessMsg("If an account exists for " + email + ", a password reset link has been sent.");
      }

      if (mode !== 'signup' && mode !== 'reset') {
        setEmail('');
        setPassword('');
        setDisplayName('');
      }
    } catch (err: any) {
      let message = "An error occurred.";
      if (!['auth/invalid-credential', 'auth/user-not-found', 'auth/wrong-password', 'auth/email-already-in-use', 'auth/weak-password'].includes(err.code)) {
        Sentry.captureException(err);
      }

      switch (err.code) {
        case 'auth/invalid-credential':
        case 'auth/wrong-password':
          message = "Incorrect email or password.";
          break;
        case 'auth/email-already-in-use':
          message = "This email is already registered.";
          break;
        case 'auth/weak-password':
          message = "Password should be at least 6 characters.";
          break;
        case 'auth/user-not-found':
          message = "No account found with this email.";
          break;
        default:
          message = err.message;
      }
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSignIn = async () => {
    setError(null);
    setLoading(true);
    const provider = new GoogleAuthProvider();
    try {
      const result = await signInWithPopup(auth, provider);
      await saveUserProfile(result.user);
      onClose();
    } catch (err: any) {
      setError(err.message);
      Sentry.captureException(err);
    } finally {
      setLoading(false);
    }
  };

  const bgClass = darkMode ? 'bg-[#0f172a] border-slate-800' : 'bg-white border-slate-200 shadow-2xl';
  const textPrimary = darkMode ? 'text-slate-100' : 'text-slate-900';
  const textSecondary = darkMode ? 'text-slate-400' : 'text-slate-600';
  const inputBg = darkMode ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-200';

  return (
    <div 
      ref={overlayRef}
      onClick={handleOverlayClick}
      className="fixed inset-0 z-[110] flex items-center justify-center px-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300"
    >
      <div className={`w-full max-w-md rounded-3xl overflow-hidden border animate-in zoom-in-95 duration-300 ${bgClass}`}>
        <div className="relative p-8">
          <button 
            onClick={onClose} 
            className="absolute top-6 right-6 text-slate-400 hover:text-green-500 transition-colors"
          >
            <X size={20} />
          </button>

          <div className="text-center mb-8">
            <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 border ${darkMode ? 'bg-green-500/10 border-green-500/20' : 'bg-green-50 border-green-100'}`}>
              {mode === 'signin' ? <LogIn className="text-green-500" size={32} /> : mode === 'signup' ? <UserPlus className="text-green-500" size={32} /> : <Lock className="text-green-500" size={32} />}
            </div>
            <h2 className={`text-3xl font-serif font-bold ${textPrimary}`}>
              {mode === 'signin' ? 'Welcome Back' : mode === 'signup' ? 'Create Account' : 'Reset Password'}
            </h2>
            <p className={`mt-2 ${textSecondary}`}>
              {mode === 'signin' 
                ? 'Sign in to access your music sanctuary.' 
                : mode === 'signup' 
                ? 'Join our community of sol-fa musicians.'
                : 'Enter your email to receive a reset link.'}
            </p>
          </div>

          <div className="space-y-4">
            {mode !== 'reset' && (
              <>
                <button 
                  onClick={handleGoogleSignIn}
                  disabled={loading}
                  className={`w-full flex items-center justify-center gap-3 py-3 rounded-xl border font-bold transition-all active:scale-95 disabled:opacity-50 ${darkMode ? 'bg-slate-900 border-slate-800 text-slate-100 hover:bg-slate-800' : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50 shadow-sm'}`}
                >
                  <svg className="w-5 h-5" viewBox="0 0 24 24">
                    <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                    <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                    <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/>
                    <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
                  </svg>
                  Continue with Google
                </button>

                <div className="relative py-2 flex items-center justify-center">
                  <div className={`flex-1 h-px ${darkMode ? 'bg-slate-800' : 'bg-slate-100'}`}></div>
                  <span className={`px-4 text-[10px] font-bold uppercase tracking-widest ${textSecondary}`}>Or continue with email</span>
                  <div className={`flex-1 h-px ${darkMode ? 'bg-slate-800' : 'bg-slate-100'}`}></div>
                </div>
              </>
            )}

            {error && (
              <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-500 text-sm flex items-start gap-2 animate-in slide-in-from-top-1 duration-200">
                <AlertCircle size={16} className="shrink-0 mt-0.5" />
                <span>{error}</span>
              </div>
            )}

            {successMsg && (
              <div className="p-3 rounded-lg bg-green-500/10 border border-green-500/20 text-green-500 text-sm flex items-start gap-2 animate-in slide-in-from-top-1 duration-200">
                <CheckCircle size={16} className="shrink-0 mt-0.5" />
                <span>{successMsg}</span>
              </div>
            )}

            <form className="space-y-4" onSubmit={handleSubmit}>
              {mode === 'signup' && (
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Display Name</label>
                  <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      type="text" 
                      value={displayName}
                      onChange={(e) => setDisplayName(e.target.value)}
                      placeholder="Enter your name"
                      className={`w-full rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}
                      required={mode === 'signup'}
                    />
                  </div>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Email Address</label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    type="email" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="name@example.com"
                    className={`w-full rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}
                    required
                  />
                </div>
              </div>

              {mode !== 'reset' && (
                <div className="space-y-1.5">
                  <div className="flex justify-between">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Password</label>
                    {mode === 'signin' && (
                      <button 
                        type="button" 
                        onClick={() => { setMode('reset'); setError(null); setSuccessMsg(null); }}
                        className="text-xs text-green-500 hover:text-green-600 font-medium"
                      >
                        Forgot Password?
                      </button>
                    )}
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      type="password" 
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="••••••••"
                      className={`w-full rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all ${inputBg} ${darkMode ? 'text-slate-200' : 'text-slate-800'}`}
                      required
                    />
                  </div>
                </div>
              )}

              <button 
                type="submit"
                disabled={loading}
                className="w-full py-3.5 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl transition-all shadow-xl shadow-green-500/20 mt-4 active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2"
              >
                {loading ? 'Processing...' : (mode === 'signin' ? 'Sign In' : mode === 'signup' ? 'Sign Up' : 'Send Reset Link')}
              </button>

              {mode === 'reset' && (
                <button 
                  type="button"
                  onClick={() => { setMode('signin'); setError(null); setSuccessMsg(null); }}
                  className={`w-full flex items-center justify-center gap-2 text-sm font-medium transition-colors ${darkMode ? 'text-slate-400 hover:text-slate-200' : 'text-slate-500 hover:text-slate-800'}`}
                >
                  <ArrowLeft size={16} />
                  Back to Sign In
                </button>
              )}
            </form>
          </div>

          <div className={`mt-8 text-center border-t pt-6 ${darkMode ? 'border-slate-800' : 'border-slate-100'}`}>
            <p className={`text-sm ${textSecondary}`}>
              {mode === 'signin' ? "Don't have an account?" : mode === 'signup' ? "Already have an account?" : "Remembered your password?"}{' '}
              <button 
                onClick={() => {
                  setMode(mode === 'signup' ? 'signin' : 'signup');
                  setError(null);
                  setSuccessMsg(null);
                }}
                className="text-green-500 hover:text-green-600 font-bold ml-1"
              >
                {mode === 'signup' ? 'Sign In' : 'Sign Up'}
              </button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

