import React, { useState, useEffect } from 'react';
import { Home, LayoutDashboard, ShieldAlert, Music, Upload, Info } from 'lucide-react';
import * as Sentry from '@sentry/react';
import Navbar from './components/Navbar';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import MusicLibrary from './components/MusicLibrary';
import AdminDashboard from './components/AdminDashboard';
import AboutPage from './components/AboutPage';
import UploadModal from './components/UploadModal';
import AuthModal from './components/AuthModal';
import FullPreviewPage from './components/FullPreviewPage';
import { View, MusicSheet } from './types';
import { auth, db } from './firebase';
// Use scoped packages to resolve missing export member errors in some environments
import { onAuthStateChanged, signOut } from '@firebase/auth';
import { collection, onSnapshot, query, orderBy, where, limit, doc, getDoc } from 'firebase/firestore';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [activePreview, setActivePreview] = useState<MusicSheet | null>(null);
  const [sheets, setSheets] = useState<MusicSheet[]>([]);

  const [currentUser, setCurrentUser] = useState<{ email: string; role: 'admin' | 'user'; emailVerified: boolean } | null>(null);

  // Deep linking logic: Check for sheet ID in URL on mount
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const sheetId = params.get('sheet');
    if (sheetId) {
      const fetchDeepLinkedSheet = async () => {
        try {
          const docRef = doc(db, 'sheets', sheetId);
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) {
            setActivePreview({ id: docSnap.id, ...docSnap.data() } as MusicSheet);
          }
        } catch (error) {
          console.error("Error fetching deep-linked sheet:", error);
          Sentry.captureException(error);
        }
      };
      fetchDeepLinkedSheet();
    }
  }, []);

  // Sync activePreview state with URL
  useEffect(() => {
    const url = new URL(window.location.href);
    if (activePreview) {
      url.searchParams.set('sheet', activePreview.id);
    } else {
      url.searchParams.delete('sheet');
    }
    window.history.replaceState({}, '', url.toString());
  }, [activePreview]);

  useEffect(() => {
    let q;

    if (currentView === 'admin' && currentUser?.role === 'admin') {
      q = query(collection(db, 'sheets'), orderBy('createdAt', 'desc'));
    } else if (currentView === 'dashboard' && currentUser) {
      q = query(
        collection(db, 'sheets'), 
        where('uploadedBy', '==', currentUser.email), 
        orderBy('createdAt', 'desc')
      );
    } else {
      q = query(
        collection(db, 'sheets'), 
        where('isPublic', '==', true), 
        orderBy('createdAt', 'desc')
      );
    }

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const sheetsData = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as MusicSheet[];

      setSheets(sheetsData);
    }, (error) => {
      console.error("Firestore sync error:", error);
      Sentry.captureException(error, {
        tags: {
          view: currentView,
          userRole: currentUser?.role || 'guest'
        }
      });

      const fallbackQ = query(collection(db, 'sheets'), limit(100));
      onSnapshot(fallbackQ, (snapshot) => {
        const sheetsData = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })) as MusicSheet[];
        setSheets(sheetsData);
      });
    });

    return () => unsubscribe();
  }, [currentView, currentUser]);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (user && user.email) {
        const role = user.email === 'vitalisnkwenti@gmail.com' ? 'admin' : 'user';
        setCurrentUser({ email: user.email, role, emailVerified: user.emailVerified });
      } else {
        setCurrentUser(null);
      }
    });
    return () => unsubscribe();
  }, []);

  const handleOpenLogin = () => {
    setIsAuthModalOpen(true);
  };

  const handleLogout = async () => {
    try {
      await signOut(auth);
      setCurrentView('home');
      setActivePreview(null);
    } catch (error) {
      console.error("Error signing out: ", error);
      Sentry.captureException(error);
    }
  };

  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  const handleHomeSearch = (query: string) => {
    setSearchQuery(query);
    setCurrentView('library');
  };

  const handlePreview = (sheet: MusicSheet) => {
    setActivePreview(sheet);
  };

  useEffect(() => {
    if (!currentUser && (currentView === 'dashboard' || currentView === 'admin')) {
      setCurrentView('home');
    }
    if (currentUser && currentUser.role !== 'admin' && currentView === 'admin') {
      setCurrentView('home');
    }
  }, [currentUser, currentView]);

  const renderView = () => {
    switch (currentView) {
      case 'home':
        return (
          <LandingPage 
            onUploadClick={currentUser ? () => setIsUploadModalOpen(true) : handleOpenLogin} 
            onBrowseClick={() => { setSearchQuery(''); setCurrentView('library'); }} 
            onSearch={handleHomeSearch}
            onPreview={handlePreview}
            isLoggedIn={!!currentUser}
            darkMode={darkMode}
            sheets={sheets}
          />
        );
      case 'dashboard':
        return currentUser ? (
          <Dashboard 
            onUploadClick={() => setIsUploadModalOpen(true)} 
            onPreview={handlePreview} 
            darkMode={darkMode}
            sheets={sheets}
            userEmail={currentUser.email}
          />
        ) : null;
      case 'library':
        return <MusicLibrary darkMode={darkMode} initialSearch={searchQuery} onPreview={handlePreview} sheets={sheets} />;
      case 'admin':
        return currentUser?.role === 'admin' ? (
          <AdminDashboard 
            onPreview={handlePreview} 
            darkMode={darkMode} 
            sheets={sheets}
          />
        ) : null;
      case 'about':
        return <AboutPage darkMode={darkMode} />;
      default:
        return <LandingPage 
          onUploadClick={currentUser ? () => setIsUploadModalOpen(true) : handleOpenLogin} 
          onBrowseClick={() => { setSearchQuery(''); setCurrentView('library'); }} 
          onSearch={handleHomeSearch}
          onPreview={handlePreview}
          isLoggedIn={!!currentUser}
          darkMode={darkMode}
          sheets={sheets}
        />;
    }
  };

  const themeClasses = darkMode 
    ? "bg-slate-950 text-slate-100" 
    : "bg-slate-50 text-slate-900";

  return (
    <div className={`min-h-screen transition-colors duration-300 selection:bg-green-500/30 selection:text-green-200 font-sans ${themeClasses}`}>
      {activePreview ? (
        <FullPreviewPage 
          sheet={activePreview} 
          darkMode={darkMode} 
          onThemeToggle={toggleTheme} 
          onClose={() => setActivePreview(null)}
          isLoggedIn={!!currentUser}
          onAuthRequired={() => setIsAuthModalOpen(true)}
        />
      ) : (
        <>
          <Navbar 
            activeView={currentView} 
            onViewChange={(view) => { setCurrentView(view); setActivePreview(null); }} 
            currentUser={currentUser}
            onLogout={handleLogout}
            onLogin={handleOpenLogin}
            darkMode={darkMode}
            onThemeToggle={toggleTheme}
          />

          <main className="max-w-7xl mx-auto px-4 pt-3 pb-12 lg:py-12 pb-24">
            {renderView()}
          </main>

          <div className={`md:hidden fixed bottom-0 left-0 right-0 backdrop-blur-lg border-t p-2 flex justify-around items-center z-50 ${darkMode ? 'bg-slate-950/80 border-slate-800' : 'bg-white/80 border-slate-200 shadow-lg'}`}>
            <button onClick={() => { setCurrentView('home'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'home' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Home size={24} />
            </button>
            <button onClick={() => { setSearchQuery(''); setCurrentView('library'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'library' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Music size={24} />
            </button>
            <button onClick={() => { setCurrentView('about'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'about' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
              <Info size={24} />
            </button>
            {currentUser && (
              <>
                <button onClick={() => setIsUploadModalOpen(true)} className="p-3 bg-green-500 text-slate-950 rounded-xl shadow-lg shadow-green-500/20 active:scale-95 transition-transform">
                  <Upload size={24} />
                </button>
                <button onClick={() => { setCurrentView('dashboard'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'dashboard' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                  <LayoutDashboard size={24} />
                </button>
                {currentUser.role === 'admin' && (
                  <button onClick={() => { setCurrentView('admin'); setActivePreview(null); }} className={`p-3 rounded-xl transition-colors ${currentView === 'admin' ? 'text-green-500' : darkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                    <ShieldAlert size={24} />
                  </button>
                )}
              </>
            )}
          </div>
        </>
      )}

      <UploadModal 
        isOpen={isUploadModalOpen} 
        onClose={() => setIsUploadModalOpen(false)} 
        darkMode={darkMode}
        userEmail={currentUser?.email || ''}
        isVerified={currentUser?.emailVerified || currentUser?.email === 'vitalisnkwenti@gmail.com'}
      />

      <AuthModal 
        isOpen={isAuthModalOpen}
        onClose={() => setIsAuthModalOpen(false)}
        darkMode={darkMode}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Download, Share2, Printer, Eye, Calendar, User, FileText, Music as MusicIcon, X, Moon, Sun, ExternalLink, Menu, ChevronUp, Loader2, AlertTriangle } from 'lucide-react';
import { MusicSheet } from '../types';
import { auth, db } from '../firebase';
import { doc, getDoc, setDoc, updateDoc, increment, serverTimestamp } from 'firebase/firestore';
import * as Sentry from '@sentry/react';

interface FullPreviewPageProps {
  sheet: MusicSheet | null;
  darkMode: boolean;
  onThemeToggle: () => void;
  onClose: () => void;
  isLoggedIn: boolean;
  onAuthRequired: () => void;
}

const FullPreviewPage: React.FC<FullPreviewPageProps> = ({ 
  sheet, 
  darkMode, 
  onThemeToggle, 
  onClose,
  isLoggedIn,
  onAuthRequired
}) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [pdfPages, setPdfPages] = useState<string[]>([]);
  const [isRendering, setIsRendering] = useState(true);

  // Logic for tracking views and downloads
  const trackInteraction = async (type: 'views' | 'downloads') => {
    if (!sheet) return;

    const user = auth.currentUser;
    const adminEmail = 'vitalisnkwenti@gmail.com';

    // 1. Filter: Admins and the uploader themselves do not count
    if (user?.email === adminEmail) return;
    if (user?.email === sheet.uploadedBy) return;

    try {
      if (user) {
        // 2a. Registered User logic: Use a Firestore ledger for absolute uniqueness
        const interactionId = `${user.uid}_${sheet.id}_${type}`;
        const interactionRef = doc(db, 'interactions', interactionId);

        // We use getDoc to check if this user has already performed this interaction
        const interactionDoc = await getDoc(interactionRef);

        if (!interactionDoc.exists()) {
          // Atomic update: increment the sheet count and record the interaction
          await setDoc(interactionRef, { 
            uid: user.uid, 
            sheetId: sheet.id, 
            type, 
            timestamp: serverTimestamp() 
          });

          await updateDoc(doc(db, 'sheets', sheet.id), {
            [type]: increment(1)
          });
        }
      } else {
        // 2b. Guest User logic: Use LocalStorage for "soft" deduplication
        const storageKey = `solfa_sanctuary_${type}_${sheet.id}`;
        if (!localStorage.getItem(storageKey)) {
          localStorage.setItem(storageKey, 'true');

          // Increment for guest view
          await updateDoc(doc(db, 'sheets', sheet.id), {
            [type]: increment(1)
          });
        }
      }
    } catch (error) {
      console.error(`Error tracking ${type}:`, error);
    }
  };

  // PDF Rendering Logic
  useEffect(() => {
    if (!sheet) return;

    const renderPdf = async () => {
      setIsRendering(true);
      setPdfPages([]);

      try {
        const pdfjsLib = (window as any).pdfjsLib;
        if (!pdfjsLib) {
          console.error("PDF.js library not found.");
          return;
        }

        // Configure the worker for PDF.js
        pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

        const loadingTask = pdfjsLib.getDocument(sheet.pdfUrl);
        const pdf = await loadingTask.promise;
        const pageImages: string[] = [];

        // Render each page for a high-quality preview
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          // Scale 2.0 for high DPI screens and better zoom clarity on mobile
          const viewport = page.getViewport({ scale: 2.0 });
          const canvas = document.createElement('canvas');
          const context = canvas.getContext('2d');

          if (context) {
            canvas.height = viewport.height;
            canvas.width = viewport.width;

            const renderContext = {
              canvasContext: context,
              viewport: viewport
            };

            await page.render(renderContext).promise;
            // Convert to JPEG with high quality to balance memory and clarity
            pageImages.push(canvas.toDataURL('image/jpeg', 0.9));
          }
        }

        setPdfPages(pageImages);
      } catch (error) {
        console.error("Error rendering PDF:", error);
        Sentry.captureException(error);
      } finally {
        setIsRendering(false);
      }
    };

    renderPdf();
  }, [sheet?.id, sheet?.pdfUrl]);

  // Track view on component mount
  useEffect(() => {
    if (sheet) {
      // Delay slightly to ensure it's a deliberate view and not a misclick
      const timer = setTimeout(() => {
        trackInteraction('views');
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [sheet?.id]);

  if (!sheet) {
    return (
      <div className={`min-h-screen flex items-center justify-center ${darkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
        <div className="text-center space-y-4">
          <MusicIcon size={64} className="mx-auto text-slate-500 opacity-20" />
          <h1 className="text-2xl font-serif font-bold">Music Sheet Not Found</h1>
          <button onClick={onClose} className="text-green-500 hover:underline">Go Back</button>
        </div>
      </div>
    );
  }

  const handleProtectedAction = (action: () => void) => {
    if (isLoggedIn) {
      action();
    } else {
      onAuthRequired();
    }
  };

  const handleOpenNewTab = () => {
    handleProtectedAction(() => {
      // Open the app with the sheet deep-linked via URL parameter
      const url = `${window.location.origin}${window.location.pathname}?sheet=${sheet.id}`;
      window.open(url, '_blank');
    });
  };

  const handleDownload = () => {
    handleProtectedAction(() => {
      trackInteraction('downloads');
      window.open(sheet.pdfUrl, '_blank');
    });
  };

  const handleShare = () => {
    handleProtectedAction(() => {
      if (navigator.share) {
        navigator.share({
          title: sheet.title,
          text: `Check out ${sheet.title} on Sol-fa Sanctuary`,
          url: window.location.href,
        }).catch(() => {});
      } else {
        navigator.clipboard.writeText(window.location.href);
        alert("Link copied to clipboard!");
      }
    });
  };

  const handlePrint = () => {
    handleProtectedAction(() => {
      window.print();
    });
