import React, { useState, useEffect } from 'react';
import { Download, Share2, Printer, Eye, Calendar, User, FileText, Music as MusicIcon, X, Moon, Sun, ExternalLink, Menu, ChevronUp, Loader2, AlertTriangle } from 'lucide-react';
import { MusicSheet } from '../types';
import { auth, db } from '../firebase';
import { doc, getDoc, setDoc, updateDoc, increment, serverTimestamp } from 'firebase/firestore';

interface FullPreviewPageProps {
  sheet: MusicSheet | null;
  darkMode: boolean;
  onThemeToggle: () => void;
  onClose: () => void;
  isLoggedIn: boolean;
  onAuthRequired: () => void;
}

const FullPreviewPage: React.FC<FullPreviewPageProps> = ({ 
  sheet, 
  darkMode, 
  onThemeToggle, 
  onClose,
  isLoggedIn,
  onAuthRequired
}) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [pdfPages, setPdfPages] = useState<string[]>([]);
  const [isRendering, setIsRendering] = useState(true);

  // Logic for tracking views and downloads
  const trackInteraction = async (type: 'views' | 'downloads') => {
    if (!sheet) return;

    const user = auth.currentUser;
    const adminEmail = 'vitalisnkwenti@gmail.com';

    // 1. Filter: Admins and the uploader themselves do not count
    if (user?.email === adminEmail) return;
    if (user?.email === sheet.uploadedBy) return;

    try {
      if (user) {
        // 2a. Registered User logic: Use a Firestore ledger for absolute uniqueness
        const interactionId = `${user.uid}_${sheet.id}_${type}`;
        const interactionRef = doc(db, 'interactions', interactionId);

        // We use getDoc to check if this user has already performed this interaction
        const interactionDoc = await getDoc(interactionRef);

        if (!interactionDoc.exists()) {
          // Atomic update: increment the sheet count and record the interaction
          await setDoc(interactionRef, { 
            uid: user.uid, 
            sheetId: sheet.id, 
            type, 
            timestamp: serverTimestamp() 
          });

          await updateDoc(doc(db, 'sheets', sheet.id), {
            [type]: increment(1)
          });
        }
      } else {
        // 2b. Guest User logic: Use LocalStorage for "soft" deduplication
        const storageKey = `solfa_sanctuary_${type}_${sheet.id}`;
        if (!localStorage.getItem(storageKey)) {
          localStorage.setItem(storageKey, 'true');

          // Increment for guest view
          await updateDoc(doc(db, 'sheets', sheet.id), {
            [type]: increment(1)
          });
        }
      }
    } catch (error) {
      console.error(`Error tracking ${type}:`, error);
    }
  };

  // PDF Rendering Logic - Highly optimized for performance
  useEffect(() => {
    if (!sheet) return;

    let blobUrls: string[] = [];

    const renderPdf = async () => {
      setIsRendering(true);
      setPdfPages([]);

      try {
        const pdfjsLib = (window as any).pdfjsLib;
        if (!pdfjsLib) {
          console.error("PDF.js library not found.");
          return;
        }

        // Configure the worker for PDF.js
        pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

        const loadingTask = pdfjsLib.getDocument(sheet.pdfUrl);
        const pdf = await loadingTask.promise;
        const pageUrls: string[] = [];

        // Render each page for a high-quality preview with async yielding
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          // High scale for crisp text, but with async yields to prevent thread choking
          const viewport = page.getViewport({ scale: 2.0 });
          const canvas = document.createElement('canvas');
          const context = canvas.getContext('2d');

          if (context) {
            canvas.height = viewport.height;
            canvas.width = viewport.width;

            await page.render({ canvasContext: context, viewport }).promise;

            // Optimization: Switch from Base64 to Blobs for 90% less memory usage
            const blob: Blob | null = await new Promise(resolve => canvas.toBlob(resolve, 'image/jpeg', 0.85));
            if (blob) {
              const url = URL.createObjectURL(blob);
              pageUrls.push(url);
              blobUrls.push(url);
            }
          }

          // Yield to main thread every page to keep UI responsive
          await new Promise(resolve => setTimeout(resolve, 0));
        }

        setPdfPages(pageUrls);
      } catch (error) {
        console.error("Error rendering PDF:", error);
      } finally {
        setIsRendering(false);
      }
    };

    renderPdf();

    // Cleanup Blob URLs on unmount to prevent severe memory leaks
    return () => {
      blobUrls.forEach(url => URL.revokeObjectURL(url));
    };
  }, [sheet?.id, sheet?.pdfUrl]);

  // Track view on component mount
  useEffect(() => {
    if (sheet) {
      // Delay slightly to ensure it's a deliberate view and not a misclick
      const timer = setTimeout(() => {
        trackInteraction('views');
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [sheet?.id]);

  if (!sheet) {
    return (
      <div className={`min-h-screen flex items-center justify-center ${darkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
        <div className="text-center space-y-4">
          <MusicIcon size={64} className="mx-auto text-slate-500 opacity-20" />
          <h1 className="text-2xl font-serif font-bold">Music Sheet Not Found</h1>
          <button onClick={onClose} className="text-green-500 hover:underline">Go Back</button>
        </div>
      </div>
    );
  }

  const handleProtectedAction = (action: () => void) => {
    if (isLoggedIn) {
      action();
    } else {
      onAuthRequired();
    }
  };

  const handleOpenNewTab = () => {
    handleProtectedAction(() => {
      const url = `${window.location.origin}${window.location.pathname}?sheet=${sheet.id}`;
      window.open(url, '_blank');
    });
  };

  const handleDownload = () => {
    handleProtectedAction(() => {
      trackInteraction('downloads');
      window.open(sheet.pdfUrl, '_blank');
    });
  };

  const handleShare = () => {
    handleProtectedAction(() => {
      if (navigator.share) {
        navigator.share({
          title: sheet.title,
          text: `Check out ${sheet.title} on Sol-fa Sanctuary`,
          url: `${window.location.origin}${window.location.pathname}?sheet=${sheet.id}`,
        }).catch(() => {});
      } else {
        navigator.clipboard.writeText(`${window.location.origin}${window.location.pathname}?sheet=${sheet.id}`);
        alert("Link copied to clipboard!");
      }
    });
  };

  const handlePrint = () => {
    handleProtectedAction(() => {
      window.print();
    });
  };

  const textPrimary = darkMode ? 'text-slate-100' : 'text-slate-900';
  const textSecondary = darkMode ? 'text-slate-400' : 'text-slate-600';
  const headerBg = darkMode ? 'bg-slate-900/95 border-slate-800' : 'bg-white/95 border-slate-200 shadow-sm';

  return (
    <div className={`fixed inset-0 flex flex-col h-screen overflow-hidden transition-colors duration-300 ${darkMode ? 'bg-slate-950' : 'bg-slate-100'}`}>
      {/* Dynamic Styles for Print Optimization */}
      <style>{`
        @media print {
          @page {
            margin: 1cm;
            size: auto;
          }
          html, body {
            height: auto !important;
            overflow: visible !important;
            background: white !important;
            color: black !important;
            margin: 0 !important;
            padding: 0 !important;
          }
          /* Override the fixed container to allow multi-page flow and remove first blank page */
          div.fixed.inset-0 {
            position: static !important;
            display: block !important;
            height: auto !important;
            overflow: visible !important;
            inset: auto !important;
            padding: 0 !important;
            margin: 0 !important;
          }
          header, .no-print {
            display: none !important;
            height: 0 !important;
            visibility: hidden !important;
          }
          main {
            padding: 0 !important;
            margin: 0 !important;
            width: 100% !important;
            overflow: visible !important;
            height: auto !important;
            position: static !important;
            display: block !important;
            will-change: auto !important;
          }
          .print-header {
            display: block !important;
            text-align: center;
            font-size: 11pt;
            font-family: serif;
            margin: 0 0 25px 0 !important;
            padding: 0 0 10px 0 !important;
            border-bottom: 1px solid #ddd;
            page-break-before: avoid;
            break-before: avoid;
          }
          .score-page-container {
            padding: 0 !important;
            margin: 0 !important;
            display: block !important;
            background: transparent !important;
            border: none !important;
            box-shadow: none !important;
            width: 100% !important;
            max-width: none !important;
          }
          .score-page {
            box-shadow: none !important;
            border: none !important;
            width: 100% !important;
            max-width: none !important;
            margin: 0 0 20px 0 !important;
            display: block !important;
            page-break-after: always;
            break-after: page;
          }
          .score-page:last-child {
            margin-bottom: 0 !important;
            page-break-after: avoid;
            break-after: avoid;
          }
          img {
            max-width: 100% !important;
            height: auto !important;
            display: block;
            margin: 0 auto;
            image-rendering: high-quality;
          }
          .hide-on-print {
            display: none !important;
          }
        }
      `}</style>

      <header className={`shrink-0 z-[100] border-b backdrop-blur-xl transition-all ${headerBg} no-print`}>
        <div className="max-w-[1920px] mx-auto px-4 md:px-6 py-1 lg:py-4">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-0.5 md:gap-6">

            <div className="flex items-center gap-4 flex-1 min-w-0">
